/**
 * MedX tooltip runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Positions contextual help text for supply-chain terminology and field hints.
 */
const TOOLTIP_PLACEMENTS = Object.freeze([
  "top",
  "top-start",
  "top-end",
  "bottom",
  "bottom-start",
  "bottom-end",
  "left",
  "right",
]);

const GLOSSARY = Object.freeze({
  sku: "Stock Keeping Unit — unique product identifier in the warehouse system.",
  lot: "Production lot number used for recall traceability and expiry tracking.",
  batch: "Inbound shipment batch grouping multiple lots from a single supplier delivery.",
  coldChain: "Temperature-controlled supply chain path requiring 2–8°C monitoring.",
  gmp: "Good Manufacturing Practice — quality standard for pharmaceutical production.",
  ndc: "National Drug Code — FDA identifier for human drug products in the US.",
  reorderPoint: "Minimum stock level that triggers automatic replenishment orders.",
  leadTime: "Expected days between placing a purchase order and receiving goods.",
  safetyStock: "Buffer inventory held to absorb demand variability or supply delays.",
  expiryFefo: "First Expiry First Out — dispatch policy prioritizing nearest expiry dates.",
});

const activeTooltips = new Map();
let tooltipDelayMs = 300;

function createTooltip(config) {
  const id = config.id ?? `medx-tooltip-${activeTooltips.size + 1}`;
  const entry = {
    id,
    triggerId: config.triggerId,
    content: config.content ?? GLOSSARY[config.term] ?? config.term ?? "",
    term: config.term ?? null,
    placement: config.placement ?? "top",
    delay: config.delay ?? tooltipDelayMs,
    visible: false,
    showTimeout: null,
    hideTimeout: null,
  };
  activeTooltips.set(id, entry);
  return entry;
}

function scheduleShow(id) {
  const entry = activeTooltips.get(id);
  if (!entry) return;
  clearTimeout(entry.hideTimeout);
  entry.showTimeout = setTimeout(() => {
    entry.visible = true;
    entry.shownAt = Date.now();
  }, entry.delay);
}

function scheduleHide(id, immediate = false) {
  const entry = activeTooltips.get(id);
  if (!entry) return;
  clearTimeout(entry.showTimeout);
  const hide = () => {
    entry.visible = false;
    entry.hiddenAt = Date.now();
  };
  if (immediate) hide();
  else entry.hideTimeout = setTimeout(hide, 100);
}

function computeTooltipPosition(triggerRect, placement, tooltipSize) {
  const gap = 8;
  const positions = {
    top: { x: triggerRect.x + triggerRect.width / 2 - tooltipSize.width / 2, y: triggerRect.y - tooltipSize.height - gap },
    bottom: { x: triggerRect.x + triggerRect.width / 2 - tooltipSize.width / 2, y: triggerRect.y + triggerRect.height + gap },
    left: { x: triggerRect.x - tooltipSize.width - gap, y: triggerRect.y + triggerRect.height / 2 - tooltipSize.height / 2 },
    right: { x: triggerRect.x + triggerRect.width + gap, y: triggerRect.y + triggerRect.height / 2 - tooltipSize.height / 2 },
  };
  const base = placement.split("-")[0];
  return positions[base] ?? positions.top;
}

function registerGlossaryTooltips(terms, triggerPrefix) {
  return terms.map((term, i) =>
    createTooltip({
      id: `${triggerPrefix}-${term}`,
      triggerId: `${triggerPrefix}-trigger-${i}`,
      term,
      placement: TOOLTIP_PLACEMENTS[i % TOOLTIP_PLACEMENTS.length],
    }),
  );
}

async function runMedxTooltip() {
  console.log("[medx:ui:tooltip] runtime initialized");
  console.log(`[medx:ui:tooltip] glossaryTerms=${Object.keys(GLOSSARY).length}`);

  const inventoryTooltips = registerGlossaryTooltips(
    ["sku", "lot", "batch", "coldChain", "reorderPoint"],
    "inventory-field",
  );

  for (const tt of inventoryTooltips.slice(0, 2)) {
    scheduleShow(tt.id);
  }

  await new Promise((resolve) => setTimeout(resolve, tooltipDelayMs + 50));

  for (const tt of inventoryTooltips) {
    scheduleHide(tt.id, true);
  }

  const mockRect = { x: 100, y: 200, width: 120, height: 32 };
  const pos = computeTooltipPosition(mockRect, "bottom", { width: 200, height: 40 });

  console.log(`[medx:ui:tooltip] registered=${activeTooltips.size}`);
  console.log("[medx:ui:tooltip] samplePosition", pos);
  console.log("[medx:ui:tooltip] bootstrap complete");
}

module.exports = runMedxTooltip;
